+/**
+ * Utility class to validate URLs and prevent SSRF attacks
+ * by blocking requests to internal/private network resources
+ */
+export class UrlValidator {
+
+  private static readonly BLOCKED_HOSTNAMES = [
+    'localhost',
+    'localhost.localdomain',
+    '127.0.0.1',
+    '::1',
+    '0.0.0.0',
+  ];
+
+  private static readonly PRIVATE_IP_PATTERNS = [
+    /^10\./,                          // 10.0.0.0/8
+    /^172\.(1[6-9]|2[0-9]|3[0-1])\./, // 172.16.0.0/12
+    /^192\.168\./,                    // 192.168.0.0/16
+    /^169\.254\./,                    // 169.254.0.0/16 (link-local, includes cloud metadata)
+    /^0\.0\.0\.0/,                    // 0.0.0.0/8
+    /^224\./,                         // Multicast 224.0.0.0/4
+    /^240\./,                         // Reserved 240.0.0.0/4
+  ];
+
+  static isValidEndpointUrl(url: string): boolean {
+    if (!url || typeof url !== 'string') {
+      return false;
+    }
+
+    try {
+      const parsedUrl = new URL(url);
+
+      if (parsedUrl.protocol !== 'http:' && parsedUrl.protocol !== 'https:') {
+        return false;
+      }
+
+      const hostname = parsedUrl.hostname.toLowerCase();
+
+      if (this.BLOCKED_HOSTNAMES.includes(hostname)) {
+        return false;
+      }
+
+      for (const pattern of this.PRIVATE_IP_PATTERNS) {
+        if (pattern.test(hostname)) {
+          return false;
+        }
+      }
+
+      return true;
+    } catch {
+      return false;
+    }
+  }
+}
