+const should = require("should");
+const { OPCUAServer, OPCUAClient } = require("node-opcua");
+
+describe("Subscription DoS Protection (CVE-2022-24375)", function () {
+    this.timeout(10000);
+
+    it("should enforce maximum subscription limit", async () => {
+        const server = new OPCUAServer({
+            port: 2222,
+        });
+
+        await server.start();
+
+        const client = OPCUAClient.create({});
+        await client.connect(server.endpoints[0].endpointUrl);
+
+        try {
+            const session = await client.createSession();
+
+            // Attempt to create subscriptions beyond the limit
+            let subscriptionCount = 0;
+            let limitReached = false;
+
+            while (!limitReached && subscriptionCount < 1100) {
+                try {
+                    await session.createSubscription({
+                        requestedPublishingInterval: 1000,
+                        requestedLifetimeCount: 100,
+                        requestedMaxKeepAliveCount: 10,
+                    });
+                    subscriptionCount++;
+                } catch (err) {
+                    err.message.should.match(/Maximum number of subscriptions/);
+                    limitReached = true;
+                }
+            }
+
+            limitReached.should.be.true("Should have reached subscription limit");
+            subscriptionCount.should.be.lessThan(1001, "Should not exceed MAX_SUBSCRIPTIONS");
+
+            await session.close();
+        } finally {
+            await client.disconnect();
+            await server.shutdown();
+        }
+    });
+});

